import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import { useToast } from '../context/ToastContext';
import { Fingerprint, User, Mail, ShieldCheck } from 'lucide-react'; // Removed Eye/EyeOff if not needed, kept Fingerprint

const RegisterPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '', confirmPassword: '' });
  const [isRegistering, setIsRegistering] = useState(false);
  const addToast = useToast();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      return addToast('VALIDATION_FAILURE: Keys do not match.', 'error');
    }

    setIsRegistering(true);
    try {
      await api.post('/auth/register', { email: formData.email, password: formData.password });
      addToast('IDENTITY_CREATED: Node active.', 'success');
      navigate('/login');
    } catch (err) {
      addToast('NODE_COLLISION: Email exists.', 'error');
    } finally {
      setIsRegistering(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#0a0a0a] font-mono p-4">
      <div className="w-full max-w-md p-8 bg-[#141414] border border-white/10 rounded-2xl shadow-2xl">
        <div className="flex flex-col items-center mb-8">
          <div className="w-14 h-14 bg-emerald-500/10 rounded-xl flex items-center justify-center mb-4 border border-emerald-500/20 text-emerald-500">
            <Fingerprint size={28} />
          </div>
          <h2 className="text-white text-xl font-bold tracking-[0.3em] uppercase">Initialize_Node</h2>
        </div>
        
        <form onSubmit={handleSubmit} className="space-y-4">
          <input 
            type="email" 
            placeholder="EMAIL_ADDR" 
            className="w-full bg-black/40 border border-white/10 p-3 rounded-lg text-white text-sm"
            onChange={(e) => setFormData({ ...formData, email: e.target.value })} 
            required 
          />
          <input 
            type="password" 
            placeholder="SECURITY_KEY" 
            className="w-full bg-black/40 border border-white/10 p-3 rounded-lg text-white text-sm"
            onChange={(e) => setFormData({ ...formData, password: e.target.value })} 
            required 
          />
          <input 
            type="password" 
            placeholder="VERIFY_KEY" 
            className="w-full bg-black/40 border border-white/10 p-3 rounded-lg text-white text-sm"
            onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })} 
            required 
          />
          <button 
            type="submit" 
            className="w-full py-4 rounded-lg font-bold uppercase text-[11px] bg-emerald-500 text-black hover:bg-emerald-400 mt-4"
          >
            Create_Analyst_Account
          </button>
        </form>
      </div>
    </div>
  );
};

export default RegisterPage;
